import React, { useState, useEffect } from 'react';
import { DndContext, DragOverlay, closestCenter, pointerWithin } from '@dnd-kit/core';
import GuestList from './components/GuestList';
import TableFloor from './components/TableFloor';
import ImportModal from './components/ImportModal';
import FilterPanel from './components/FilterPanel';
import AutoAssignModal from './components/AutoAssignModal';
import './App.css';

const API_URL = 'http://localhost:3001/api';

function App() {
  const [projectId, setProjectId] = useState(null);
  const [project, setProject] = useState(null);
  const [guests, setGuests] = useState([]);
  const [tables, setTables] = useState([]);
  const [showImport, setShowImport] = useState(false);
  const [showAutoAssign, setShowAutoAssign] = useState(false);
  const [filters, setFilters] = useState({});
  const [sortBy, setSortBy] = useState('name');
  const [searchQuery, setSearchQuery] = useState('');
  const [activeGuest, setActiveGuest] = useState(null);
  const [isManager, setIsManager] = useState(true);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const path = window.location.pathname;
    const id = path.split('/')[1];

    if (id && id.length === 36) {
      setProjectId(id);
      setIsManager(!window.location.pathname.endsWith('/view'));
      loadProject(id);
    } else {
      createNewProject();
    }
  }, []);

  const loadProject = async (id) => {
    try {
      const res = await fetch(`${API_URL}/projects/${id}`);
      const data = await res.json();
      setProject(data);
      setGuests(data.guests || []);
      setTables(data.tables || []);
    } catch (err) {
      console.error('Failed to load project:', err);
    } finally {
      setLoading(false);
    }
  };

  const createNewProject = async () => {
    try {
      const res = await fetch(`${API_URL}/projects`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: 'Annual Dinner', guests: [], tables: [] })
      });
      const data = await res.json();
      window.history.replaceState(null, '', `/${data.id}`);
      setProjectId(data.id);
      setProject(data);
      setGuests([]);
      setTables([]);
    } catch (err) {
      console.error('Failed to create project:', err);
    } finally {
      setLoading(false);
    }
  };

  const saveProject = async (newGuests, newTables) => {
    if (!projectId || !isManager) return;
    try {
      await fetch(`${API_URL}/projects/${projectId}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ guests: newGuests, tables: newTables })
      });
    } catch (err) {
      console.error('Failed to save:', err);
    }
  };

  const addTable = (seats) => {
    const newTable = {
      id: `table-${Date.now()}`,
      name: `Table ${tables.length + 1}`,
      seats: seats || 10,
      guests: []
    };
    const newTables = [...tables, newTable];
    setTables(newTables);
    saveProject(guests, newTables);
  };

  const updateTable = (tableId, updates) => {
    const newTables = tables.map(t => t.id === tableId ? { ...t, ...updates } : t);
    setTables(newTables);
    saveProject(guests, newTables);
  };

  const removeTable = (tableId) => {
    const table = tables.find(t => t.id === tableId);
    const newGuests = [...guests];
    const newTables = tables.filter(t => t.id !== tableId);

    table?.guests.forEach(guestId => {
      const guest = guests.find(g => g.id === guestId);
      if (guest) guest.tableId = null;
    });

    setGuests(newGuests);
    setTables(newTables);
    saveProject(newGuests, newTables);
  };

  const assignGuest = (guestId, tableId) => {
    const newGuests = guests.map(g => {
      if (g.id === guestId) {
        return { ...g, tableId };
      }
      return g;
    });

    const table = tables.find(t => t.id === tableId);
    if (!table) return;

    const newTables = tables.map(t => {
      if (t.id === tableId) {
        const guestIds = t.guests.filter(id => id !== guestId);
        if (!guestIds.includes(guestId)) guestIds.push(guestId);
        return { ...t, guests: guestIds };
      }
      if (t.guests.includes(guestId)) {
        return { ...t, guests: t.guests.filter(id => id !== guestId) };
      }
      return t;
    });

    setGuests(newGuests);
    setTables(newTables);
    saveProject(newGuests, newTables);
  };

  const handleImport = (importedGuests) => {
    const newGuests = importedGuests.map((g, i) => ({
      ...g,
      id: `guest-${Date.now()}-${i}`,
      tableId: null
    }));
    const updatedGuests = [...guests, ...newGuests];
    setGuests(updatedGuests);
    saveProject(updatedGuests, tables);
  };

  const handleDeleteGuest = (guestId) => {
    const guest = guests.find(g => g.id === guestId);
    const newGuests = guests.filter(g => g.id !== guestId);
    const newTables = tables.map(t => ({
      ...t,
      guests: t.guests.filter(id => id !== guestId)
    }));
    setGuests(newGuests);
    setTables(newTables);
    saveProject(newGuests, newTables);
  };

  const exportAssignments = () => {
    const data = tables.map(t => ({
      table: t.name,
      seats: t.seats,
      guests: t.guests.map(gid => {
        const g = guests.find(g => g.id === gid);
        return g ? g.name : '';
      }).filter(Boolean)
    }));

    const unassigned = guests.filter(g => !g.tableId).map(g => g.name);

    let csv = 'Table,Seats,Guests\n';
    data.forEach(row => {
      csv += `"${row.table}",${row.seats},"${row.guests.join('; ')}"\n`;
    });
    csv += '\nUnassigned Guests\n';
    unassigned.forEach(name => csv += `${name}\n`);

    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `table-assignments-${project?.name || 'export'}.csv`;
    a.click();
  };

  const getFilteredGuests = () => {
    let filtered = guests.filter(g => !g.tableId);

    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      filtered = filtered.filter(g =>
        Object.values(g).some(v => String(v).toLowerCase().includes(q))
      );
    }

    Object.entries(filters).forEach(([field, value]) => {
      if (value && value !== 'all') {
        filtered = filtered.filter(g => String(g[field]) === value);
      }
    });

    filtered.sort((a, b) => {
      if (sortBy === 'name') return (a.name || '').localeCompare(b.name || '');
      return String(a[sortBy] || '').localeCompare(String(b[sortBy] || ''));
    });

    return filtered;
  };

  const getCustomFields = () => {
    if (!guests.length) return [];
    const fields = new Set();
    guests.forEach(g => {
      Object.keys(g).forEach(k => {
        if (!['id', 'tableId', 'name'].includes(k)) fields.add(k);
      });
    });
    return Array.from(fields);
  };

  const handleDragStart = (event) => {
    const guest = guests.find(g => g.id === event.active.id);
    setActiveGuest(guest);
  };

  const handleDragEnd = (event) => {
    setActiveGuest(null);
    const { active, over } = event;
    if (!over) return;

    const guestId = active.id;
    const tableId = over.id;

    if (tableId.startsWith('table-')) {
      assignGuest(guestId, tableId);
    } else if (tableId === 'unassigned') {
      assignGuest(guestId, null);
    }
  };

  if (loading) {
    return <div className="loading">Loading...</div>;
  }

  return (
    <DndContext
      collisionDetection={pointerWithin}
      onDragStart={handleDragStart}
      onDragEnd={handleDragEnd}
    >
      <div className="app">
        <header className="header">
          <div className="header-left">
            <h1>Table Management</h1>
            {project && <span className="project-name">{project.name}</span>}
          </div>
          <div className="header-right">
            {isManager && (
              <>
                <button onClick={() => setShowImport(true)} className="btn">Import Guests</button>
                <button onClick={() => setShowAutoAssign(true)} className="btn">Auto Assign</button>
                <button onClick={exportAssignments} className="btn btn-secondary">Export</button>
                <div className="share-link">
                  <span>Share: </span>
                  <input
                    readOnly
                    value={`${window.location.origin}/${projectId}/view`}
                    onClick={e => e.target.select()}
                  />
                </div>
              </>
            )}
            {!isManager && <span className="view-only-badge">View Only</span>}
          </div>
        </header>

        {isManager && (
          <FilterPanel
            guests={guests}
            filters={filters}
            setFilters={setFilters}
            sortBy={sortBy}
            setSortBy={setSortBy}
            searchQuery={searchQuery}
            setSearchQuery={setSearchQuery}
            customFields={getCustomFields()}
          />
        )}

        <main className="main">
          {isManager ? (
            <>
              <GuestList
                guests={getFilteredGuests()}
                onDelete={handleDeleteGuest}
              />
              <TableFloor
                tables={tables}
                guests={guests}
                onAddTable={addTable}
                onUpdateTable={updateTable}
                onRemoveTable={removeTable}
              />
            </>
          ) : (
            <TableFloor
              tables={tables}
              guests={guests}
              readOnly
            />
          )}
        </main>

        {showImport && (
          <ImportModal
            onClose={() => setShowImport(false)}
            onImport={handleImport}
          />
        )}

        {showAutoAssign && (
          <AutoAssignModal
            guests={guests}
            tables={tables}
            customFields={getCustomFields()}
            onClose={() => setShowAutoAssign(false)}
            onAssign={(assignments) => {
              const newGuests = guests.map(g => ({
                ...g,
                tableId: assignments[g.id] || null
              }));
              const newTables = tables.map(t => ({
                ...t,
                guests: Object.entries(assignments)
                  .filter(([, tid]) => tid === t.id)
                  .map(([gid]) => gid)
              }));
              setGuests(newGuests);
              setTables(newTables);
              saveProject(newGuests, newTables);
            }}
          />
        )}

        <DragOverlay>
          {activeGuest && (
            <div className="guest-card dragging">{activeGuest.name}</div>
          )}
        </DragOverlay>
      </div>
    </DndContext>
  );
}

export default App;
